/* color-cards.css */
.hrxo-color-card-grid {
  --card-gap: 12px;
  display: grid;
  gap: var(--card-gap);
  padding: var(--card-gap);
  grid-template-columns: repeat(auto-fit, minmax(240px, 1fr));
  max-width: 1440px;
  margin: 0 auto;
}

.hrxo-color-card {
  position: relative;
  border-radius: 8px;
  padding: 1rem;
  box-shadow: 0 2px 12px rgba(0,0,0,0.08);
  min-height: 100px;
  overflow: hidden;
  color: white;
  border: 1px solid rgba(255,255,255,0.1);
  background: var(--card-bg);
  display: flex;
  flex-direction: column;
}

.hrxo-color-card-overlay {
  position: absolute;
  top: 0;
  left: 0;
  right: 0;
  bottom: 0;
  background: linear-gradient(135deg, rgba(0,0,0,0.05) 0%, transparent 70%);
  pointer-events: none;
}

.hrxo-color-card-header {
  font-size: 1.1rem;
  font-weight: 600;
  margin-bottom: 0.5rem;
  text-shadow: 0 1px 2px rgba(0,0,0,0.2);
  position: relative;
  z-index: 1;
  text-align: center;
  flex-shrink: 0;
}

.hrxo-color-card-values {
  background: rgba(255, 255, 255, 0.12);
  backdrop-filter: blur(4px);
  padding: 0.8rem;
  border-radius: 6px;
  display: grid;
  gap: 0.8rem;
  grid-template-columns: repeat(2, 1fr);
  flex: 1;
  min-height: 60px;
}

.hrxo-color-card-values.has-cmyk {
  grid-template-columns: repeat(3, 1fr);
}

.hrxo-color-item {
  display: flex;
  flex-direction: column;
  justify-content: center;
  align-items: center;
  padding: 0.2rem;
  min-width: 0;
}

.hrxo-color-card-label {
  font-size: 0.68rem;
  opacity: 0.9;
  letter-spacing: 0.03em;
  margin-bottom: 0.1rem;
  white-space: nowrap;
}

.hrxo-color-card-data {
  font-size: 0.82rem;
  font-family: 'Menlo', monospace;
  font-weight: 500;
  letter-spacing: -0.01em;
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
  max-width: 100%;
}

/* 响应式设计 */
@media (max-width: 480px) {
  .hrxo-color-card-grid {
    grid-template-columns: 1fr;
  }

  .hrxo-color-card-values {
    grid-template-columns: 1fr !important;
    gap: 0.6rem;
  }

  .hrxo-color-item {
    flex-direction: row;
    justify-content: space-between;
    padding: 0.3rem 0.8rem;
    background: rgba(0,0,0,0.05);
    border-radius: 4px;
  }

  .hrxo-color-card-label {
    margin-bottom: 0;
    margin-right: 0.8rem;
  }
}

@media (min-width: 768px) {
  .hrxo-color-card {
    min-height: 95px;
    padding: 1rem 0.8rem;
  }

  .hrxo-color-card-values {
    padding: 0.6rem;
    gap: 0.6rem;
  }

  .hrxo-color-card-label {
    font-size: 0.65rem;
  }

  .hrxo-color-card-data {
    font-size: 0.78rem;
  }
}

@media (min-width: 1280px) {
  .hrxo-color-card-grid {
    --card-gap: 16px;
  }
}

